        dp[i][1] = prefix_xor[i]
    }
    for (j in 2..k.toInt()) {
        for (i in j..n.toInt()) {
            var min_val = Long.MAX_VALUE
            for (m in (j - 1)..(i - 1)) {
                val current_max = Math.max(dp[m][j - 1], prefix_xor[i] xor prefix_xor[m])
                if (current_max < min_val) {
                    min_val = current_max
                }
            }
            dp[i][j] = min_val
        }
    }
    return dp[n.toInt()][k.toInt()]
